#include <bits/stdc++.h>
using namespace std;
int dp[100005],w[100005],v[100005],s,n,d;
int main()
{
    cin>>s>>n>>d;
    for(int i=1;i<=d;i++) cin>>w[i]>>v[i];
    for(int k=1;k<=n;k++)
    {
        int m=s/1000;
        for(int i=1;i<=d;i++)   
        {
            for(int j=w[i]/1000;j<=m;j++)
            {
                if(w[i]/1000<=j)dp[j]=max(dp[j],dp[j-w[i]/1000]+v[i]);
            }
        }
        s+=dp[m];
        memset(dp,0,sizeof(dp));
    }
    cout<<s;
    return 0;
}
